  nickname?: string;
  suffix: string;
  title: string;
};

export type AddressSectionProps = Pick<
  FormAddressControlProps,
  'fieldPrefix' | 'fieldPrefixDelimiter' | 'isRequired' | 'showLine2'
> & {
  addressLabel?:
    | 'street'
    | 'mailing'
    | 'residential'
    | 'employer'
    | 'pac'
    | 'business'
    | 'organization';
  addressType?: 'complete' | 'international' | 'zip';
  displayAddress?: boolean;
  regions?: string[];
};

export type NameAndOrganizationsFieldProps = {
  actionPage?: PublicActionPage;
  displayCommunicationsConsent?: boolean;
  displayEmail?: boolean;
  displayPhone?: boolean;
  formKeys?: NameFieldFormKeys;
  includeFirstName?: boolean;
  includeLastName?: boolean;
  includeMiddleName?: boolean;
  includeOrganization?: boolean;
  includeSuffix?: boolean;
  includeTitle?: boolean;
  requireEmail?: boolean;
  requireEmailOrPhone?: boolean;
  requireFirstAndLastName?: boolean;
  requirePhone?: boolean;
  requireTitle?: boolean;
} & Omit<AddressSectionProps, 'isRequired'> & { requireAddress?: boolean };

const AddressSection = ({
  addressLabel,
  addressType,
  displayAddress = true,
  fieldPrefix,
  fieldPrefixDelimiter,
  isRequired,
  regions,
  showLine2,
}: AddressSectionProps) => {
  const { watch } = useFormContext();
  const { t } = useTranslation('customFields');
  const label = useMemo(() => t(`address.${addressLabel ?? 'street'}`), [addressLabel, t]);
  const donorProfile = watch('donorProfile');

  const allowedCountries = useMemo(
    () =>
      regions?.includes('IN')
        ? undefined
        : regions?.length
          ? regions
          : addressType === 'complete'
            ? ['US']
            : undefined,
    [addressType, regions]
  ) as FormAddressControlProps['allowedCountries'];

  if (
    !displayAddress ||
    (fieldPrefix === 'addressAttributes' &&
      donorProfile &&
      donorProfile.line1 &&
      donorProfile.city &&
      donorProfile.region &&
      donorProfile.postalCode &&
      donorProfile.country) ||
    (addressType === 'zip' && donorProfile && donorProfile.postalCode)
  ) {
    return null;
  }

  return (
    <div className="-mb-2 flex flex-col items-stretch">
      {addressType === 'zip' ? (
        <FormPostalCodeControl
          isRequired={isRequired}
          name={`${fieldPrefix}${fieldPrefixDelimiter}postalCode`}
        />
      ) : (
        <FormAddressControl
          allowedCountries={allowedCountries}
          fieldPrefix={fieldPrefix}
          fieldPrefixDelimiter={fieldPrefixDelimiter}
          isRequired={isRequired}
          label={label}
          showLine2={showLine2}
        />
      )}
    </div>
  );
};

